import { streamText } from 'ai';
import { openai } from '@ai-sdk/openai';
import { createRAGRetriever } from './rag';

export async function streamSupportResponse(query: string) {
  const retriever = createRAGRetriever();
  const context = await retriever.retrieve(query);

  const result = await streamText({
    model: openai('gpt-4o'),
    prompt: `Context: ${context}\n\nCustomer: ${query}\nSupport Agent:`,
    maxTokens: 1000,
  });

  return result.toAIStreamResponse();
}

