import { NextRequest } from 'next/server';
import { streamSupportResponse } from './support-agent';

export const runtime = 'edge';

export async function POST(req: NextRequest) {
  try {
    const { messages } = await req.json();
    const lastMessage = messages[messages.length - 1].content;

    const stream = await streamSupportResponse(lastMessage);

    return new Response(stream, {
      headers: {
        'Access-Control-Allow-Origin': '*',
        'Content-Type': 'text/plain; charset=utf-8',
      },
    });
  } catch (error) {
    return new Response('Error', { status: 500 });
  }
}

import { Pinecone } from '@pinecone-database/pinecone';

export async function createRAGRetriever() {
  const pinecone = new Pinecone({ apiKey: process.env.PINECONE_API_KEY! });
  const index = pinecone.index('support-docs');

  return {
    async retrieve(query: string) {
      const queryEmbedding = await getEmbedding(query);
      const results = await index.query({
        vector: queryEmbedding,
        topK: 5,
        includeMetadata: true,
      });
      return results.matches.map((m) => m.metadata?.text).join('\n');
    },
  };
}

