import { createVex } from '@vex_dev/sdk';
import { generateText } from 'ai';

const vex = createVex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!,
});

export async function safeGenerateText(prompt: string, context: string) {
  const rawResult = await generateText({
    model: openai('gpt-4o'),
    prompt: `${context}\n\n${prompt}`,
  });

  const verified = await vex.verify({
    input: prompt + context,
    output: rawResult.text,
    checks: {
      accuracy: { against: context },
      pii: { block: true },
      tone: { consistent: 'professional,empathetic' },
      policy: { support: true },
    },
  });

  if (!verified.pass) {
    throw new Error(`Vex blocked: ${verified.issues.join(', ')}`);
  }

  return rawResult;
}

import { streamText } from 'ai';
import { createVexStreamMiddleware } from '@vex_dev/sdk';

const vexMiddleware = createVexStreamMiddleware({
  projectId: 'your-project-id',
  checks: {
    partialHallucination: { threshold: 0.8 },
    pii: { stream: true },
    escalation: { keywords: ['refund', 'cancel', 'urgent'] },
  },
});

export async function safeStreamText(query: string, context: string) {
  return streamText({
    model: openai('gpt-4o'),
    prompt: `Context: ${context}\nCustomer: ${query}`,
    middleware: [vexMiddleware],
  }).pipeThrough(vexMiddleware.transformStream);
}

